import React, { useState, useEffect } from 'react';
// 🎨 Import all our Premium Pages
import Login from './pages/Login';
import StudentHome from './pages/StudentHome';
import AddProject from './pages/AddProject';
import AdminDashboard from './pages/AdminDashboard';
import ProjectDetails from './pages/ProjectDetails';

function App() {
  // --- 🚦 NAVIGATION & STATE MANAGEMENT ---
  const [currentPage, setCurrentPage] = useState('login');
  const [user, setUser] = useState(null);
  const [selectedProject, setSelectedProject] = useState(null);

  // 🔄 SESSION CHECK: Keeps user logged in on refresh
  useEffect(() => {
    const savedUser = localStorage.getItem('user_info');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      setCurrentPage('home');
    }
  }, []);

  // 🔐 AUTH LOGIC
  const handleLogin = (userData) => {
    setUser(userData);
    setCurrentPage('home');
  };

  const handleLogout = () => {
    localStorage.removeItem('user_info');
    setUser(null);
    setCurrentPage('login');
  };

  // --- 🗺️ ROUTING LOGIC ---
  return (
    <div className="App selection:bg-indigo-500/30">
      
      {/* 1. LOGIN PAGE */}
      {currentPage === 'login' && (
        <Login onLogin={handleLogin} />
      )}
      
      {/* 2. STUDENT HOME PAGE */}
      {currentPage === 'home' && (
        <StudentHome 
          onNavigate={(page) => setCurrentPage(page)} 
          onViewProject={(project) => {
            setSelectedProject(project);
            setCurrentPage('details');
          }}
          onLogout={handleLogout}
        />
      )}

      {/* 3. ADD PROJECT FORM */}
      {currentPage === 'add-project' && (
        <AddProject onNavigate={(page) => setCurrentPage(page)} />
      )}

      {/* 4. ADMIN DASHBOARD (Faculty View) */}
      {currentPage === 'admin' && (
        <AdminDashboard onNavigate={(page) => setCurrentPage(page)} />
      )}
      
      {/* 5. PROJECT DETAILS VIEW */}
      {currentPage === 'details' && (
         <ProjectDetails 
            project={selectedProject} 
            onBack={() => setCurrentPage('home')} 
         />
      )}

    </div>
  );
}

export default App;
